// Parse AI competitive intelligence output
const output = $input.first().json.output || '';

// Extract each section
const contentTypeMatch = output.match(/CONTENT_TYPE:\s*([\s\S]*?)(?=\nMESSAGING_ANGLE:|$)/);
const messagingMatch = output.match(/MESSAGING_ANGLE:\s*([\s\S]*?)(?=\nKEY_CLAIMS:|$)/);
const keyClaimsMatch = output.match(/KEY_CLAIMS:\s*([\s\S]*?)(?=\nTARGET_AUDIENCE_SIGNALS:|$)/);
const targetAudienceMatch = output.match(/TARGET_AUDIENCE_SIGNALS:\s*([\s\S]*?)(?=\nPRICING_OFFER_SIGNALS:|$)/);
const pricingMatch = output.match(/PRICING_OFFER_SIGNALS:\s*([\s\S]*?)(?=\nSTRENGTHS_IDENTIFIED:|$)/);
const strengthsMatch = output.match(/STRENGTHS_IDENTIFIED:\s*([\s\S]*?)(?=\nWEAKNESSES_GAPS:|$)/);
const weaknessesMatch = output.match(/WEAKNESSES_GAPS:\s*([\s\S]*?)(?=\nOPPORTUNITY_FOR_US:|$)/);
const opportunityMatch = output.match(/OPPORTUNITY_FOR_US:\s*([\s\S]*?)(?=\nURGENCY_SCORE:|$)/);
const urgencyScoreMatch = output.match(/URGENCY_SCORE:\s*([\d]+)/);
const urgencyReasoningMatch = output.match(/URGENCY_REASONING:\s*([\s\S]*)$/);

const contentType = contentTypeMatch ? contentTypeMatch[1].trim() : 'Other';
const messagingAngle = messagingMatch ? messagingMatch[1].trim() : '';
const keyClaims = keyClaimsMatch ? keyClaimsMatch[1].trim() : '';
const targetAudience = targetAudienceMatch ? targetAudienceMatch[1].trim() : '';
const pricingSignals = pricingMatch ? pricingMatch[1].trim() : 'None detected';
const strengths = strengthsMatch ? strengthsMatch[1].trim() : '';
const weaknesses = weaknessesMatch ? weaknessesMatch[1].trim() : '';
const opportunity = opportunityMatch ? opportunityMatch[1].trim() : '';
const urgencyScore = urgencyScoreMatch ? parseInt(urgencyScoreMatch[1]) : 5;
const urgencyReasoning = urgencyReasoningMatch ? urgencyReasoningMatch[1].trim() : '';

// Get video data
const videoUrl = $('2. Google Sheets — Read Pending Videos').item.json['Video URL'];
const videoTitle = $('2. Google Sheets — Read Pending Videos').item.json['Video Title'];
const competitorName = $('2. Google Sheets — Read Pending Videos').item.json['Competitor Name'];
const ourBrand = $('2. Google Sheets — Read Pending Videos').item.json['Your Product / Brand'];

// Get summary data
const summary = $('5. WayinVideo — Get Summary Results').item.json.data.summary || '';
const tags = Array.isArray($('5. WayinVideo — Get Summary Results').item.json.data.tags)
  ? $('5. WayinVideo — Get Summary Results').item.json.data.tags.join(', ')
  : '';

// Get current week Monday
const today = new Date();
const weekStart = new Date(today);
weekStart.setDate(today.getDate() - today.getDay() + 1);
const weekDate = weekStart.toISOString().split('T')[0];

return [{
  json: {
    weekDate,
    competitorName,
    videoTitle,
    videoUrl,
    ourBrand,
    contentType,
    messagingAngle,
    keyClaims,
    targetAudience,
    pricingSignals,
    strengths,
    weaknesses,
    opportunity,
    urgencyScore,
    urgencyReasoning,
    summary,
    tags
  }
}];
